import{_ as o,c as e,o as t,d as c}from"./app.8cee1528.js";var r="/blog-press/assets/710.d1d5d275.jpg";const q='{"title":"2022-7-6","description":"","frontmatter":{},"headers":[{"level":2,"title":"2022-7-6","slug":"_2022-7-6"},{"level":2,"title":"2022-7-8","slug":"_2022-7-8"},{"level":2,"title":"2022-7-12","slug":"_2022-7-12"}],"relativePath":"read/99_Qs.md","lastUpdated":1657637927000}',l={},s=c('<h2 id="_2022-7-6" tabindex="-1">2022-7-6</h2><p><strong>\u7231\u610F\u8FD9\u79CD\u4E1C\u897F\uFF0C\u611F\u53D7\u4E0D\u5230\uFF0C\u5C31\u662F\u6CA1\u6709</strong></p><blockquote><p>\u2003\u2003 \u7231\u4E0D\u4F1A\u6D88\u5931\uFF0C\u53EA\u4F1A\u8F6C\u79FB\uFF0C\u90A3\u4E2A\u4EBA\u6CA1\u8DDF\u4F60\u8BF4\u7684\u8BDD\uFF0C\u6CA1\u8DDF\u4F60\u5206\u4EAB\u7684\u4E8B\uFF0C\u4ED6\u4F1A\u548C\u522B\u4EBA\u8BF4\uFF0C\u548C\u522B\u4EBA\u5206\u4EAB\u3002\u5305\u62EC\u4F60\u6CA1\u8BF4\u8FC7\u7684\u8BDD\uFF0C\u4F60\u6CA1\u5206\u4EAB\u8FC7\u7684\u4E8B\uFF0C\u4E5F\u4E00\u5B9A\u4F1A\u6709\u522B\u4EBA\u548C\u4ED6\u5206\u4EAB\uFF0C\u4E0D\u8981\u6000\u7591\uFF0C\u5728\u5BF9\u4F60\u51B7\u6DE1\u7684\u65F6\u5019\uFF0C\u4ED6\u90FD\u5728\u6342\u70ED\u522B\u4EBA\u3002<br> \u2003\u2003\u5145\u6EE1\u65B0\u9C9C\u611F\u7684\u604B\u7231\u521D\u671F\uFF0C\u662F\u5206\u4EAB\u6B32\u6700\u65FA\u76DB\u7684\u9636\u6BB5\uFF0C\u51FA\u4E86\u65B0\u53E3\u5473\u7684\u5976\u8336\uFF0C\u770B\u4E86\u5F88\u597D\u770B\u7684\u5267\uFF0C\u62AC\u5934\u649E\u89C1\u7684\u665A\u971E\u6709\u4E91\u6735\u5F62\u72B6\u5F88\u53EF\u7231,\u4ED6\u603B\u662F\u60F3\u7740\u628A\u5F53\u4E0B\u53D1\u751F\u5728\u81EA\u5DF1\u8EAB\u4E0A\u7684\u4E8B\u60C5\uFF0C\u7B2C\u4E00\u65F6\u95F4\u5206\u4EAB\u7ED9\u5FC3\u91CC\u7684\u90A3\u4E2A\u4EBA\uFF0C\u54EA\u6015\u4E8B\u60C5\u65E0\u5173\u7D27\u8981\u3002<br> \u2003\u2003\u5206\u4EAB\u7684\u672C\u610F\u662F\u5E0C\u671B\u4F60\u80FD\u53C2\u4E0E\u6211\u7684\u751F\u6D3B,\u5F00\u5FC3\u7684\u4E0D\u662F\u8BB2\u5E9F\u8BDD,\u800C\u662F\u5373\u4F7F\u8BB2\u4E86\u4E00\u5806\u5E9F\u8BDD,\u5BF9\u65B9\u8FD8\u662F\u4F1A\u8BA4\u771F\u7684\u56DE\u590D.\u540E\u6765\u554A,\u4E5F\u8BB8\u662F\u6CA1\u6709\u5F97\u5230\u56DE\u5E94,<strong><code>\u4E5F\u8BB8\u662F\u7231\u610F\u6E10\u6DE1</code></strong>\u3002<br> \u2003\u2003\u5206\u4EAB\u6B32\u53D8\u6210\u4E86\u6B32\u8A00\u53C8\u6B62,\u53C8\u53D8\u6210\u4E86\u65E0\u8BDD\u53EF\u8BF4\u3002\u8FD9\u65F6\u624D\u53D1\u73B0\u4ED6\u624B\u4E0A\u7684\u521B\u53EF\u8D34\u4E0B \u662F\u4F60\u4ECE\u672A\u77E5\u6653\u7684\u4F24\u53E3<br> \u2003\u2003\u6211\u4EEC\u7684\u5206\u4EAB\u6B32\u90FD\u8F6C\u79FB\u5230\u4E86\u53E6\u5916\u7684\u5730\u65B9,\u4E0D\u662F\u6CA1\u6709\u751F\u6D3B,\u53EA\u662F\u6CA1\u6709\u5206\u4EAB\u7ED9\u4F60\u4E86,\u56E0\u4E3A\u5206\u4EAB\u6B32\u662F\u9700\u8981\u9760\u56DE\u5E94\u6765\u5EF6\u7EED\u7684,\u800C\u788E\u788E\u5FF5\u4E5F\u53EA\u60F3\u7ED9\u6709\u56DE\u5E94\u7684\u4EBA\u542C\u3002<br> \u2003\u2003\u300A\u5B8C\u7F8E\u964C\u751F\u4EBA\u300B\u4E2D\u6709\u8FD9\u6837\u4E00\u53E5\u8BDD\uFF0C\u5982\u679C\u4F60\u6BCF\u5929\u8981\u548C\u5979\u8BF4\u4E0A30\u5206\u949F\u7684\u8BDD\uFF0C\u90A3\u5C31\u662F\u7231\u4E0A\u5979\u4E86\u3002\u540C\u6837\uFF0C\u5982\u679C\u653E\u773C\u671B\u53BB\u804A\u5929\u6846 \u5C31\u50CF\u4F60\u7684\u7559\u8A00\u677F\uFF0C\u53EF\u4EE5\u786E\u5B9A\u7684\u662F\uFF0C\u5979\u4E0D\u7231\u4F60\u4E86\u3002<br> \u2003\u2003\u5931\u53BB\u5206\u4EAB\u6B32\u662F\u6563\u573A\u7684\u5F00\u59CB\uFF0C\u56E0\u4E3A\u5728\u4EB2\u5BC6\u5173\u7CFB\u91CC\uFF0C\u5206\u4EAB\u6B32\u5C31\u50CF\u7275\u8FDE\u8FD9\u4E24\u4E2A\u4EBA\u7684\u7EF3\u5B50\uFF0C\u6211\u6446\u52A8\u7EF3\u5B50\u7684\u8FD9\u4E00\u7AEF\uFF0C\u4F60\u5728\u90A3\u4E00\u7AEF\u5C31\u80FD\u611F\u53D7\u5F97\u5230\uFF0C\u5982\u679C\u4E00\u65B9\u6CA1\u6709\u611F\u53D7\u5230\u56DE\u5E94\uFF0C\u53EA\u80FD\u8BF4\u660E\u5BF9\u9762\u7684\u4EBA\u5DF2\u7ECF\u653E\u624B\u4E86\u3002<br> \u2003\u2003\u4E3A\u4EC0\u4E48\u4E0D\u613F\u610F\u627F\u8BA4\u7B80\u5355\u7684\u4E8B\u5B9E\u5462\uFF1F\u5979\u53EA\u662F\u6CA1\u90A3\u4E48\u559C\u6B22\u4F60\u800C\u5DF2\u3002<strong><code>\u627F\u8BA4\u5427</code></strong>\uFF0C\u5982\u679C\u5979\u559C\u6B22\u4F60\uFF0C\u4E00\u5B9A\u8FEB\u4E0D\u53CA\u5F85\u7684\u60F3\u89C1\u4F60\uFF0C\u65F6\u65F6\u523B\u523B\u8054\u7CFB\u4F60\u3002\u522B\u88AB\u9A97\uFF0C\u4E5F\u522B\u548C\u5979\u4E00\u8D77\u9A97\u81EA\u5DF1 \u7231\u610F\u8FD9\u79CD\u4E1C\u897F\u611F\u53D7\u4E0D\u5230\uFF0C\u5C31\u662F\u6CA1\u6709\u3002</p></blockquote><h2 id="_2022-7-8" tabindex="-1">2022-7-8</h2><p><strong>\u61C2\u5F97\u72EC\u5904\u662F\u6210\u719F\u7684\u6807\u5FD7</strong> \u2003\u2003<code>25\u8981\u4E0D\u5C31\u7ED3\u5A5A\u597D\u597D\u751F\u6D3B\u8981\u4E0D\u5C31\u8086\u610F\u7684\u81EA\u7531\u7684\u6D3B\u7740 \u2014\u2014\u2014\u2014 \u661F</code></p><blockquote><p><strong><code>\u8086\u610F\u7684\u81EA\u7531\uFF08\u5B64\u72EC\uFF09\u7684\u6D3B\u7740</code></strong><br> \u2003\u2003\u6709\u4EBA\u8BF4\uFF0C\u61C2\u5F97\u72EC\u5904\u662F\u4E00\u79CD\u6210\u719F\u7684\u8868\u73B0\u3002\u7684\u786E\uFF0C\u5927\u5343\u4E16\u754C\u91CC \u6BCF\u4E2A\u4EBA\u90FD\u662F\u6765\u53BB\u5306\u5306\uFF0C\u6CA1\u6709\u8C01\u4F1A\u6C38\u8FDC\u966A\u5728\u4F60\u8EAB\u8FB9\uFF0C\u5F88\u591A\u65F6\u5019\uFF0C\u4F60\u5C31\u5B66\u4F1A\u5982\u4F55\u8DDF\u5B64\u8EAB\u4E00\u4EBA\u7684\u81EA\u5DF1\u597D\u597D\u76F8\u5904\uFF0C\u624D\u4E0D\u4F1A\u8F7B\u6613\u7684\u88AB\u751F\u6D3B\u91CC\u7684\u8270\u96BE\u6253\u8D25\u3002<br> \u2003\u2003\u5728\u8FD9\u4E2A\u8FC7\u7A0B\u4E2D\uFF0C\u96BE\u514D\u4F1A\u6709\u4F24\u5FC3\uFF0C\u4F1A\u6709\u65E0\u52A9\uFF0C\u4F46\u662F \u53EA\u8981\u4F60\u80FD\u591F\u575A\u5F3A\u7684\u8D70\u8FC7\uFF0C\u4FBF\u662F\u6700\u597D\u7684\u6210\u957F\uFF0C\u54EA\u6015\u5728\u6CA1\u6709\u4EBA\u966A\u4F34\uFF0C\u6CA1\u6709\u4EBA\u5618\u5BD2\u95EE\u6696\u7684\u65E5\u5B50\u91CC\uFF0C\u4F60\u4E5F\u53EF\u4EE5\u4E00\u4E2A\u4EBA\u5403\u996D\uFF0C\u4E00\u4E2A\u4EBA\u4E0A\u73ED\uFF0C\u4E00\u4E2A\u4EBA\u8D70\u8DEF\u56DE\u5BB6\uFF0C\u4E0D\u518D\u5E7B\u60F3\u7740\u8C01\u4F1A\u966A\u4F60\u4E00\u8F88\u5B50\u3002<br> \u2003\u2003\u6709\u65F6\u5019\uFF0C\u5373\u4FBF\u5F88\u6E34\u671B\u6709\u4E2A\u4F34\uFF0C\u53EF\u4E5F\u4F1A\u8BA9\u81EA\u5DF1\u4E60\u60EF\uFF0C\u5373\u4FBF\u5185\u5FC3\u5F88\u8106\u5F31\uFF0C\u53EF\u4E5F\u4F1A\u4F2A\u88C5\u6210\u575A\u5F3A\u7684\u6A21\u6837\uFF0C\u5373\u4FBF\u6709\u5F88\u591A\u8BDD\u60F3\u8BF4\uFF0C\u53EF\u4E5F\u4F1A\u72EC\u81EA\u4E00\u4EBA\u6D88\u5316\uFF0C\u56E0\u4E3A\uFF0C\u6BCF\u4E2A\u4EBA\u90FD\u6709\u81EA\u5DF1\u8981\u8D70\u7684\u8DEF\uFF0C\u6CA1\u6709\u4EBA\u80FD\u966A\u4F60\u4E00\u76F4\u8D70\u4E0B\u53BB\u3002\u6BCF\u4E2A\u4EBA\u90FD\u8981\u81EA\u5DF1\u8981\u505A\u7684\u4E8B\uFF0C\u6CA1\u6709\u4EBA\u80FD\u4E49\u65E0\u53CD\u987E\u7684\u62A4\u4F60\u4E00\u4E16\u5468\u5168\u3002\u8FD9\u4E2A\u4E16\u754C\u4E0A\u548C\u4F60\u76F8\u5904\u65F6\u95F4\u6700\u591A\u7684\uFF0C\u6700\u4E86\u89E3\u4F60\u7684\u4EBA\uFF0C\u7EC8\u7A76\u8FD8\u662F\u4F60\u81EA\u5DF1\u3002<br> \u2003\u2003\u6240\u4EE5\u4F60\u8981\u61C2\u5F97\u5982\u679C\u5B89\u987F\u4E00\u4E2A\u4EBA\u7684\u65F6\u5149\uFF0C\u5F53\u6CA1\u6709\u4EBA\u66FF\u4F60\u906E\u98CE\u6321\u96E8\u7684\u65F6\u5019\uFF0C\u8981\u597D\u597D\u7167\u987E\u81EA\u5DF1\u3002</p></blockquote><blockquote><p><strong><code>\u201C\u65E0\u7231\u3001\u65E0\u8BDD\u3001\u65E0\u6027\u201D</code></strong><br> \u2003\u2003(<code>\u65E0\u7231</code>)<br> \u2003\u2003\u5A5A\u59FB\u5927\u591A\u5F00\u59CB\u4E8E\u7231\u60C5\uFF0C\u4F46\u5F88\u591A\u65F6\u5019\uFF0C\u7231\u60C5\u53CD\u800C\u88AB\u5A5A\u59FB\u8017\u5C3D\u3002<br> \u2003\u2003\u5A5A\u59FB\u6CA1\u6709\u4E86\u7231\u60C5\uFF0C\u4EB2\u60C5\u4E5F\u4E0D\u591F\u7A33\u56FA\uFF0C\u4E24\u4E2A\u4EBA\u66F4\u50CF\u662F\u642D\u4F19\u8FC7\u65E5\u5B50\uFF0C\u5408\u4F5C\u517B\u5B69\u5B50\uFF0C\u6CA1\u6709\u4E86\u6B47\u65AF\u5E95\u91CC\u7684\u5435\u95F9\uFF0C\u6CA1\u6709\u4F60\u6B7B\u6211\u6D3B\u7684\u4E89\u593A\uFF0C\u5A5A\u59FB\u53EA\u5269\u4E0B\u6C89\u9ED8\uFF0C\u751F\u6D3B\u4E2D\u8FD9\u6837\u7684\u60C5\u51B5\u6BD4\u6BD4\u7686\u662F\uFF0C\u8FD9\u5927\u6982\u5C31\u662F\u65E0\u7231\u5A5A\u59FB\u7684\u771F\u662F\u5199\u7167\u5427\u3002<br> \u2003\u2003<code>(\u65E0\u8BDD)</code><br> \u2003\u2003\u5218\u9707\u4E91\u66FE\u7ECF\u8BF4\u8FC7\uFF0C\u4E00\u4E2A\u4EBA\u7684\u5B64\u72EC\u4E0D\u662F\u5B64\u72EC\uFF0C\u4E00\u4E2A\u4EBA\u627E\u53E6\u4E00\u4E2A\u4EBA\uFF0C\u4E00\u53E5\u8BDD\u627E\u53E6\u4E00\u53E5\u8BDD\uFF0C\u624D\u662F\u771F\u6B63\u7684\u5B64\u72EC\u3002<br> \u2003\u2003......<br> \u2003\u2003<code>(\u65E0\u6027)</code><br> \u2003\u2003......</p></blockquote><h2 id="_2022-7-12" tabindex="-1">2022-7-12</h2><p><strong>\u6211\u6700\u5927\u7684\u9057\u61BE\uFF0C\u662F\u4F60\u7684\u9057\u61BE\u4E0E\u6211\u6709\u5173</strong></p><blockquote><p>\u2003\u2003\u300A\u540E\u6765\u7684\u6211\u4EEC\u300B\u4E2D\u6709\u8FD9\u6837\u4E00\u53E5\u53F0\u8BCD\uFF0C\u6211\u6CE8\u5B9A\u4E0D\u662F\u966A\u4F60\u8D70\u5230\u6700\u540E\u7684\u90A3\u4E2A\u4EBA\uFF0C\u4F46\u662F \u6211\u6CE8\u5B9A\u662F\u9047\u89C1\u4F60\u7684\u4EBA\uFF0C\u6700\u5927\u7684\u9057\u61BE\uFF0C\u662F\u4F60\u7684\u9057\u61BE\u4E0E\u6211\u6709\u5173\u3002</p></blockquote><blockquote><p>\u2003\u2003\u66FE\u6709\u4E2A\u4EBA\uFF0C\u4F60\u77E5\u9053\u6CE8\u5B9A\u4E0D\u53EF\u80FD\u62E5\u6709\uFF0C\u4F46\u662F\u8FD8\u662F\u4F1A\u60F3\u5FF5\u5979\u3002\u6216\u8BB8\u5206\u5F00\u624D\u662F\u5E38\u6001\uFF0C\u6211\u4EEC\u4E5F\u90FD\u6CA1\u6709\u4F8B\u5916\u3002\u4EA6\u6216\u8BB8\u4E0D\u518D\u8054\u7CFB\uFF0C\u662F\u5BF9\u6211\u4EEC\u6765\u8BF4\u662F\u6700\u597D\u7684\u9009\u62E9\uFF0C\u4E5F\u662F\u5BF9\u5F7C\u6B64\u6700\u771F\u8BDA\u7684\u9ED8\u5951\u3002</p></blockquote><blockquote><p>\u2003\u2003\u5173\u4E8E\u5979\u7684\u56DE\u5FC6\uFF0C\u6211\u4F9D\u7136\u8BB0\u5F97\u66FE\u4E0E\u5979\u5728\u5E7F\u573A\u5439\u8FC7\u7684\u665A\u98CE\uFF0C\u4EE5\u53CA\u6563\u843D\u5728\u98CE\u4E2D\u90A3\u4E9B\u65E0\u6CD5\u5151\u73B0\u7684\u8BFA\u8A00\u3002\u4F9D\u7136\u8BB0\u5F97\uFF0C\uFF0C</p></blockquote><blockquote><p>\u2003\u2003\u5076\u5C14\u4E5F\u4F1A\u5E86\u5E78\uFF0C\u6BD4\u8D77\u9EEF\u6DE1\u6536\u573A\uFF0C\u5982\u4ECA\u7684\u7ED3\u5C40\u8981\u597D\u5F88\u591A\u3002\u867D\u7136\u7559\u6709\u9057\u61BE\uFF0C\u4F46\u8FD9\u6837\u7684\u9057\u61BE\u672A\u5C1D\u4E0D\u662F\u4E00\u79CD\u6210\u5168\u3002</p></blockquote><blockquote><p>\u2003\u2003\u662F\u4ECE\u672A\u5728\u4E00\u8D77\u66F4\u9057\u61BE\uFF0C\u8FD8\u662F\u6700\u7EC8\u6CA1\u6709\u5728\u4E00\u8D77\u66F4\u9057\u61BE\uFF1F \u2003\u2003\u5176\u5B9E\u4E0D\u7BA1\u662F\u5728\u4E00\u8D77\u8FD8\u662F\u6CA1\u6709\u5728\u4E00\u8D77\uFF0C\u90FD\u6709\u9057\u61BE \u3002\u800C\u90A3\u4EFD\u9057\u61BE\u3002\u8BF4\u5230\u5E95\u8FD8\u662F\u4E0D\u7518\uFF0C\u662F\u610F\u96BE\u5E73\u3002\u6709\u4EBA\u8BF4\u6700\u7EC8\u6CA1\u6709\u5728\u4E00\u8D77\u66F4\u9057\u61BE\uFF0C\u660E\u660E\u90FD\u5728\u4E00\u8D77\u4E86\uFF0C\u4E3A\u4EC0\u4E48\u6CA1\u80FD\u8D70\u5230\u6700\u540E\u5462\uFF1F\u662F\u6211\u4E0D\u591F\u597D\uFF0C\u8FD8\u662F\u4F60\u4E0D\u591F\u597D\uFF1F\u90A3\u4E48\u52AA\u529B\u4E86\u4E3A\u4EC0\u4E48\u8FD8\u4F1A\u5206\u5F00\uFF1F</p></blockquote><blockquote><p>\u2003\u2003\u4E8E\u6211\u800C\u8A00\u5462\uFF0C\u9057\u61BE\u7684\u662F\u672A\u5F00\u59CB\u5C31\u5DF2\u7ECF\u7ED3\u675F\uFF0C\u518D\u4E5F\u6CA1\u4E86\u7136\u540E\u3002\u6211\u4E0D\u6562\u53D1\u6D88\u606F\u7ED9\u5979\u5206\u4EAB\uFF0C\u60F3\u53D1\u670B\u53CB\u5708\u4E0E\u5979\u5206\u4EAB\uFF0C\u5C31\u5FD8\u4E86\u6211\u4EEC\u65E9\u5DF2\u4E0D\u662F<code>\u597D\u53CB</code>\u3002\u5C31\u50CF\u53D1\u73B0\u4ECA\u5929\u7684\u4E91\u5F88\u597D\u770B\uFF0C\u60F3\u5230\u7684\u7B2C\u4E00\u4EF6\u4E8B\u5C31\u662F\u62CD\u7ED9\u5979\uFF0C\u540E\u6765\u60F3\u60F3\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u597D\u4E45\u6CA1\u6709\u8054\u7CFB\u4E86\uFF0C\u624D\u53D1\u73B0\u3000\u4E91\u6CA1\u90A3\u4E48\u597D\u770B\u3002 \u770B\u4E86\u770B\u6211\u4EEC\u7684\u804A\u5929\u8BB0\u5F55\uFF0C\u597D\u50CF\u5979\u662F\u771F\u7684\u5728\u4E4E\u8FC7\u6211\uFF0C\u5C31\u60F3\u8BF4\u591A\u4E86\u6015\u6211\u70E6\uFF0C\u8BF4\u5C11\u4E86\u6015\u6211\u4E0D\u660E\u767D\u3002</p></blockquote><blockquote><p>\u2003\u2003\u6709\u4E9B\u8BDD\u5C31\u50CF\u5361\u5728\u4E86\u5589\u5499\uFF0C\u8FDB\u9000\u4E24\u96BE\uFF0C\u4ECE\u6765\u6CA1\u6709\u5728\u4E00\u8D77\u662F\u6267\u5FF5\uFF0C\u90A3\u4E48\u7231\u5979\uFF0C\u5374\u8FDE\u62B1\u4E00\u4E0B\u7684\u8D44\u683C\u90FD\u6CA1\u6709\u3002</p></blockquote><blockquote><p>\u2003\u2003\u5176\u5B9E\u6211\u672C\u53EF\u4EE5\u5FCD\u53D7\u9ED1\u6697\uFF0C\u5982\u679C\u4E0D\u66FE\u89C1\u8FC7\u5149\u660E\u7684\u8BDD\u3002 <div style="width:100%;display:flex;justify-content:flex-end;"><img style="width:500px;" src="'+r+'" title="\u82B1\u90FD\u6E56"></div></p></blockquote>',17),d=[s];function b(p,_,n,u,a,i){return t(),e("div",null,d)}var g=o(l,[["render",b]]);export{q as __pageData,g as default};
